// Check if email has attachments and extract metadata
// n8n Outlook simplified output: from is a string, bodyPreview is the body
const email = $input.first().json;

// Handle both simplified (string) and raw (object) from field
let fromAddress = '';
let fromName = '';
if (typeof email.from === 'string') {
  fromAddress = email.from;
  fromName = email.from.split('@')[0];
} else if (email.from?.emailAddress) {
  fromAddress = email.from.emailAddress.address || '';
  fromName = email.from.emailAddress.name || '';
}

const result = {
  messageId: email.id,
  subject: email.subject || '',
  from: fromAddress,
  fromName: fromName,
  receivedAt: email.receivedDateTime || new Date().toISOString(),
  bodyContent: email.bodyPreview || email.body?.content || '',
  bodyType: 'text',
  hasAttachments: email.hasAttachments || false,
  conversationId: email.conversationId || '',
  internetMessageId: email.internetMessageId || ''
};

return [{ json: result }];

// Build the Claude API request
// Combine email body + attachment content for parsing
const emailMeta = $('Extract Email Metadata').first().json;
const attachments = $input.all().map(item => item.json);

// Build content array for Claude
const contentParts = [];

// Add email body context
contentParts.push({
  type: 'text',
  text: `Email Subject: ${emailMeta.subject}\nFrom: ${emailMeta.fromName} <${emailMeta.from}>\nReceived: ${emailMeta.receivedAt}\n\nEmail Body:\n${emailMeta.bodyContent}`
});

// Add attachment content
for (const att of attachments) {
  if (att.contentBytes) {
    const mimeType = att.contentType || 'application/octet-stream';
    const name = att.name || 'attachment';

    // For PDFs and images, send as base64 document/image
    if (mimeType === 'application/pdf') {
      contentParts.push({
        type: 'document',
        source: {
          type: 'base64',
          media_type: 'application/pdf',
          data: att.contentBytes
        }
      });
    } else if (mimeType.startsWith('image/')) {
      contentParts.push({
        type: 'image',
        source: {
          type: 'base64',
          media_type: mimeType,
          data: att.contentBytes
        }
      });
    } else {
      // For XLSX, DOCX, CSV — decode base64 and send as text
      // n8n will handle the base64 content
      try {
        const decoded = Buffer.from(att.contentBytes, 'base64').toString('utf-8');
        contentParts.push({
          type: 'text',
          text: `\n--- Attachment: ${name} ---\n${decoded}`
        });
      } catch (e) {
        contentParts.push({
          type: 'text',
          text: `\n--- Attachment: ${name} (binary, could not decode as text) ---`
        });
      }
    }
  }
}

return [{
  json: {
    contentParts,
    emailMeta
  }
}];

// Parse email body directly when no attachments
const emailMeta = $('Extract Email Metadata').first().json;

const contentParts = [{
  type: 'text',
  text: `Email Subject: ${emailMeta.subject}\nFrom: ${emailMeta.fromName} <${emailMeta.from}>\nReceived: ${emailMeta.receivedAt}\n\nEmail Body:\n${emailMeta.bodyContent}`
}];

return [{
  json: {
    contentParts,
    emailMeta
  }
}];

// Parse Claude's response and prepare Supabase inserts
const response = $input.first().json;
const emailMeta = $('Extract Email Metadata').first().json;

// Extract the text content from OpenRouter response (OpenAI format)
let responseText = '';
if (response.choices && response.choices.length > 0) {
  responseText = response.choices[0].message?.content || '';
} else if (response.content && Array.isArray(response.content)) {
  responseText = response.content.map(c => c.text || '').join('');
} else if (typeof response.content === 'string') {
  responseText = response.content;
}

// Parse the JSON from Claude's response
let parsed;
try {
  // Remove any markdown code fences if present
  const cleaned = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Failed to parse Claude response as JSON: ${e.message}\n\nResponse: ${responseText.substring(0, 500)}`);
}

const source = parsed.source;
const lanes = parsed.lanes || [];
const flags = parsed.flags || [];

// Compute completeness score for each lane
const requiredFields = ['origin_port', 'origin_country', 'destination_port', 'destination_country', 'equipment_type', 'base_rate', 'currency', 'valid_from', 'valid_to'];
const optionalFields = ['origin_region', 'destination_region', 'commodity_type', 'fsc_method', 'transit_days', 'route_type', 'free_time_days'];

const scoredLanes = lanes.map(lane => {
  const requiredFilled = requiredFields.filter(f => lane[f] != null && lane[f] !== '').length;
  const optionalFilled = optionalFields.filter(f => lane[f] != null && lane[f] !== '').length;
  const score = Math.round(((requiredFilled / requiredFields.length) * 0.7 + (optionalFilled / optionalFields.length) * 0.3) * 100) / 100;
  return { ...lane, completeness_score: score };
});

// Count flagged lanes
const incompleteLanes = scoredLanes.filter(l => l.completeness_score < 0.6);
const flaggedLanes = flags.filter(f => f.lane_index !== null);

// Track Claude usage
const usage = {
  model: response.model || 'anthropic/claude-sonnet-4',
  input_tokens: response.usage?.prompt_tokens || 0,
  output_tokens: response.usage?.completion_tokens || 0
};

return [{
  json: {
    source,
    lanes: scoredLanes,
    flags,
    incompleteLanes,
    emailMeta,
    usage,
    laneCount: scoredLanes.length,
    flagCount: flags.length
  }
}];

// Get the source ID from Supabase response and prepare lane inserts
const supabaseResponse = $input.first().json;
const sourceId = Array.isArray(supabaseResponse) ? supabaseResponse[0].id : supabaseResponse.id;
const parseData = $('Parse Claude Response').first().json;

// Map each lane to a Supabase insert
const laneInserts = parseData.lanes.map(lane => ({
  source_id: sourceId,
  mode: parseData.source.mode,
  origin_port: lane.origin_port,
  origin_country: lane.origin_country,
  origin_region: lane.origin_region,
  destination_port: lane.destination_port,
  destination_country: lane.destination_country,
  destination_region: lane.destination_region,
  equipment_type: lane.equipment_type,
  commodity_type: lane.commodity_type,
  base_rate: lane.base_rate,
  currency: lane.currency || 'USD',
  fsc_method: lane.fsc_method,
  fsc_value: lane.fsc_value,
  fsc_index_source: lane.fsc_index_source,
  surcharges: lane.surcharges || {},
  transit_days: lane.transit_days,
  route_type: lane.route_type,
  free_time_days: lane.free_time_days,
  valid_from: lane.valid_from || parseData.source.term_start,
  valid_to: lane.valid_to || parseData.source.term_end,
  validity_status: 'current',
  completeness_score: lane.completeness_score,
  raw_source_excerpt: lane.raw_source_excerpt
}));

return [{
  json: {
    sourceId,
    laneInserts,
    parseData
  }
}];

// Build confirmation email body
const parseData = $('Parse Claude Response').first().json;
const source = parseData.source;
const sourceId = $('Prepare Lane Inserts').first().json.sourceId;
const lanes = parseData.lanes;
const flags = parseData.flags;
const emailMeta = parseData.emailMeta;

// Build equipment type summary
const equipTypes = [...new Set(lanes.map(l => l.equipment_type).filter(Boolean))];

// Build incomplete lanes list
const incompleteLanes = lanes
  .map((l, i) => ({ ...l, index: i }))
  .filter(l => l.completeness_score < 0.6);

let body = `Filed to rate library:\n`;
body += `  Source: ${source.carrier_name || 'Unknown'}`;
if (source.contract_number) body += ` Contract ${source.contract_number}`;
if (source.amendment_number) body += `, Amendment ${source.amendment_number}`;
body += `\n`;
body += `  Mode: ${(source.mode || 'unknown').charAt(0).toUpperCase() + (source.mode || 'unknown').slice(1)}\n`;
if (source.term_start || source.term_end) {
  body += `  Term: ${source.term_start || '?'} - ${source.term_end || '?'}\n`;
}
body += `  Lanes captured: ${lanes.length}\n`;
if (equipTypes.length) body += `  Equipment types: ${equipTypes.join(', ')}\n`;
if (source.free_time_days) body += `  Free time: ${source.free_time_days} days\n`;
if (source.fsc_methodology) body += `  FSC methodology: ${source.fsc_methodology}\n`;
body += `\n`;
body += `Source ID: ${sourceId}\n`;

if (incompleteLanes.length > 0) {
  body += `\n${incompleteLanes.length} lane(s) flagged incomplete:\n`;
  for (const l of incompleteLanes) {
    body += `  - ${l.origin_port || '?'} -> ${l.destination_port || '?'}, ${l.equipment_type || '?'}\n`;
  }
}

if (flags.length > 0) {
  body += `\n${flags.length} flag(s):\n`;
  for (const f of flags) {
    body += `  - ${f.field}: ${f.reason}\n`;
  }
}

body += `\nReply to this thread if corrections are needed.`;

// Build subject line
let subject = `Re: ${emailMeta.subject}`;
if (!subject.toLowerCase().includes('rate')) {
  subject = `Re: ${emailMeta.subject} - Rates Filed`;
}

return [{
  json: {
    subject,
    body,
    replyTo: emailMeta.from,
    messageId: emailMeta.messageId,
    sourceId,
    parseData
  }
}];
